class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def find_nth_from_end(head: ListNode, n: int) -> ListNode:
    if not head:
        return None

    slow = head
    fast = head

    # Move fast pointer n steps ahead
    for _ in range(n):
        if not fast:
            # n is greater than the length of the list
            return None
        fast = fast.next

    # Move both pointers until fast reaches the end
    while fast:
        slow = slow.next
        fast = fast.next

    # At this point, slow points to the Nth node from the end
    return slow
